function jsq(items,x,y,w,h){
const tot=items.reduce((s,d)=>s+d.e,0);
if(!items.length||!tot||w<=0||h<=0)return[];
const out=[];let rem=[...items].sort((a,b)=>b.e-a.e);
let cx=x,cy=y,cw=w,ch=h;
while(rem.length){
const rT=rem.reduce((s,d)=>s+d.e,0);const wide=cw>=ch,side=wide?ch:cw;
let row=[rem[0]],best=1e9;
for(let i=0;i<=rem.length;i++){
const tr=rem.slice(0,i+1),tT=tr.reduce((s,d)=>s+d.e,0);
const sl=(tT/rT)*(wide?cw:ch);let worst=0;
for(const it of tr){const iS=(it.e/tT)*side;worst=Math.max(worst,Math.max(sl/iS,iS/sl));}
if(worst<=best){row=tr;best=worst;}else break;}
const rowT=row.reduce((s,d)=>s+d.e,0),rF=rowT/rT;
if(wide){const rW=cw*rF;let ry=cy;
for(const it of row){const iH=ch*(it.e/rowT);out.push({...it,x:cx,y:ry,w:rW,h:iH});ry+=iH;}
cx+=rW;cw-=rW;}else{const rH=ch*rF;let rx=cx;
for(const it of row){const iW=cw*(it.e/rowT);out.push({...it,x:rx,y:cy,w:iW,h:rH});rx+=iW;}
cy+=rH;ch-=rH;}
rem=rem.filter(d=>!row.includes(d));}return out;}
const jfmt=n=>n>=1000?(n/1000).toFixed(1).replace(/\.0$/,"")+"M":n+"K";
const jfW=w=>"$"+Math.round(w/1000)+"K";
function JTM({groups,colors,onDrill,W,H}){
const[hov,setHov]=useState(null);
const rects=useMemo(()=>jsq(groups,2,2,W-4,H-4),[groups,W,H]);
return(<svg width={W} height={H} style={{display:"block"}}>
{rects.map((r,i)=>{
const isH=hov===i,c=colors[r.n]||"#5B8C85";
const sh=r.w>46&&r.h>24,sn=r.w>58&&r.h>38,sw=r.w>80&&r.h>54;
const fs=Math.min(13.5,Math.max(8,Math.sqrt(r.w*r.h)/14));
const mx=Math.floor(r.w/(fs*0.52));
return(<g key={r.n+i} onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)}
onClick={()=>r.items&&onDrill(r)} style={{cursor:r.items?"pointer":"default"}}>
<rect x={r.x+1} y={r.y+1} width={Math.max(0,r.w-2)} height={Math.max(0,r.h-2)}
rx={4} fill={isH?c:c+"CC"} stroke={isH?"#FFF":"rgba(0,0,0,0.2)"}
strokeWidth={isH?1.5:0.5} style={{transition:"fill 0.12s"}}/>
{sh&&<text x={r.x+r.w/2} y={r.y+r.h/2-(sn?fs*0.55:0)} textAnchor="middle" dominantBaseline="central"
fill="#FFF" fontSize={fs} fontWeight={600} fontFamily="system-ui,sans-serif"
style={{pointerEvents:"none",textShadow:"0 1px 3px rgba(0,0,0,0.5)"}}>
{r.n.length>mx?r.n.slice(0,mx-1)+"…":r.n}</text>}
{sn&&<text x={r.x+r.w/2} y={r.y+r.h/2+fs*0.5} textAnchor="middle" dominantBaseline="central"
fill="rgba(255,255,255,0.65)" fontSize={fs-1.5} fontFamily="system-ui,sans-serif"
style={{pointerEvents:"none"}}>{jfmt(r.e)}</text>}
{sw&&<text x={r.x+r.w/2} y={r.y+r.h/2+fs*0.5+(fs-1)*1.1} textAnchor="middle" dominantBaseline="central"
fill="rgba(255,255,255,0.35)" fontSize={fs-2.5} fontFamily="system-ui,sans-serif"
style={{pointerEvents:"none"}}>avg {jfW(r.wg)}</text>}
</g>);})}
</svg>);}
