const jgroups=useMemo(()=>{
if(jIsNaics){return JN.map(s=>({n:s.n,e:s.e,wg:s.w,items:s.occs.map(o=>({n:o.n,e:o.e,wg:o.w}))}));}
const m={};
for(const o of JO){const k=o[jlens.f];if(!m[k])m[k]={n:k,e:0,ws:0,items:[]};
m[k].e+=o.e;m[k].ws+=o.e*o.w;m[k].items.push({n:o.n,e:o.e,wg:o.w});}
return Object.values(m).map(g=>({...g,wg:Math.round(g.ws/g.e)})).sort((a,b)=>b.e-a.e);
},[jlens,jIsNaics]);
const jdg=jdr?jgroups.find(g=>g.n===jdr):null;
const jdisplay=jdg?[...jdg.items].sort((a,b)=>b.e-a.e):jgroups;
const jcolorMap=useMemo(()=>{
if(jdg){const c=jlens.c[jdg.n]||(jIsNaics?NC[jdg.n]:null)||"#5B8C85";
return Object.fromEntries(jdg.items.map(o=>[o.n,c]));}
return jIsNaics?NC:jlens.c;
},[jdg,jlens,jIsNaics]);
