function Placeholder({ onBack, title }) {
  return (
    <div style={{ minHeight: "100vh", background: "#FAFAFA" }}>
      <BackBtn onClick={onBack} />
      <div style={{ textAlign: "center", padding: "120px 40px" }}>
        <h1 style={{ fontFamily: "Georgia, serif", fontSize: 36, fontWeight: 400, color: "#111", marginBottom: 12 }}>{title}</h1>
        <p style={{ fontSize: 16, color: "#999" }}>This idea is still being designed. Check back soon.</p>
      </div>
    </div>
  );
}

const pageMap = { linda: Linda, entropy: Entropy, biophilia: Biophilia, fragilemoney: FragileMoney, assumption: Assumption, whichpast: WhichPast, pendulum: Pendulum, bach: Bach, evidencediet: EvidenceDiet, incremental: Incremental, montale: Montale, jobs: Jobs };

export default function IdeaMuseum() {
  const [page, setPage] = useState(null);
  const goHome = () => { setPage(null); window.scrollTo(0, 0); };
  const goTo = (id) => { setPage(id); window.scrollTo(0, 0); };
  if (page) {
    const Component = pageMap[page];
    if (Component) return <Component onBack={goHome} />;
    const idea = ideas.find((i) => i.id === page);
    return <Placeholder onBack={goHome} title={idea ? idea.title : "Coming Soon"} />;
  }
  return <Home onNavigate={goTo} />;
}
